def ansi_shadow_banner(text: str) -> tuple[str, ...]:
    rows = [""] * 7
    for position, char in enumerate(text.lower()):
        glyph = ANSI_SHADOW.get(char, ANSI_SHADOW[" "])
        for index, line in enumerate(glyph):
            if position:
                rows[index] += " "
            rows[index] += line
    while rows and not rows[0].strip():
        rows.pop(0)
    while rows and not rows[-1].strip():
        rows.pop()
    return tuple(row.rstrip() for row in rows)
